import { useUIStore, useAuthStore, useConversationStore } from '../../store';
import Sidebar from './Sidebar';
import ChatView from '../chat/ChatView';
import VoiceView from '../voice/VoiceView';
import { useEffect } from 'react';

export default function Layout() {
  const { mode, sidebarOpen, setSidebarOpen, currentConversationId, setCurrentConversationId } = useUIStore();
  const { user, isLoggedIn } = useAuthStore();
  const { fetchConversations } = useConversationStore();

  useEffect(() => {
    fetchConversations();
  }, [isLoggedIn]);

  const handleNewChat = () => {
    setCurrentConversationId(null);
  };

  return (
    <div className="h-full flex flex-col bg-primary-50 relative">
      {/* Top bar */}
      <header className="flex-shrink-0 flex items-center justify-between px-4 py-3 bg-white/80 backdrop-blur-sm border-b border-primary-100 z-10">
        <button
          onClick={() => setSidebarOpen(true)}
          className="p-2 -ml-1 rounded-lg hover:bg-primary-100 transition-colors"
          aria-label="Open sidebar"
        >
          <svg className="w-6 h-6 text-primary-700" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
          </svg>
        </button>

        <h1 className="text-lg font-semibold text-gray-800">
          {mode === 'chat' ? 'AI Chat' : 'AI Voice'}
        </h1>

        <button
          onClick={handleNewChat}
          className="p-2 -mr-1 rounded-lg hover:bg-primary-100 transition-colors"
          aria-label="New conversation"
        >
          <svg className="w-6 h-6 text-primary-700" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
        </button>
      </header>

      {/* Main content */}
      <main className="flex-1 overflow-hidden">
        {mode === 'chat' ? <ChatView /> : <VoiceView />}
      </main>

      {/* Sidebar overlay */}
      <Sidebar />

      {/* Shadow overlay when sidebar is open */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 bg-black/30 z-20 md:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useUIStore, useAuthStore, useConversationStore } from '../../store';
import type { Conversation } from '../../types';

export default function Sidebar() {
  const { sidebarOpen, setSidebarOpen, setCurrentConversationId, currentConversationId, setMode, mode } = useUIStore();
  const { user, isLoggedIn } = useAuthStore();
  const { conversations, deleteConversation, fetchConversations } = useConversationStore();
  const [searchText, setSearchText] = useState('');
  const [showUserMenu, setShowUserMenu] = useState(false);

  const filteredConversations = useMemo(() => {
    if (!searchText.trim()) return conversations;
    const q = searchText.toLowerCase();
    return conversations.filter(
      (c) =>
        c.title.toLowerCase().includes(q) ||
        c.last_message_preview?.toLowerCase().includes(q)
    );
  }, [conversations, searchText]);

  // Group by time
  const grouped = useMemo(() => {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const yesterday = new Date(today.getTime() - 86400000);

    const groups: { label: string; items: Conversation[] }[] = [];
    const todayItems: Conversation[] = [];
    const yesterdayItems: Conversation[] = [];
    const olderItems: Conversation[] = [];

    filteredConversations.forEach((c) => {
      const d = c.created_at ? new Date(c.created_at) : now;
      if (d >= today) todayItems.push(c);
      else if (d >= yesterday) yesterdayItems.push(c);
      else olderItems.push(c);
    });

    if (todayItems.length) groups.push({ label: '今天', items: todayItems });
    if (yesterdayItems.length) groups.push({ label: '昨天', items: yesterdayItems });
    if (olderItems.length) groups.push({ label: '更早', items: olderItems });

    return groups;
  }, [filteredConversations]);

  const handleSelectConversation = (id: string) => {
    setCurrentConversationId(id);
    setSidebarOpen(false);
  };

  const handleDeleteConversation = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('确认删除这个对话？')) {
      await deleteConversation(id);
      if (currentConversationId === id) {
        setCurrentConversationId(null);
      }
    }
  };

  const handleNewChat = () => {
    setCurrentConversationId(null);
    setSidebarOpen(false);
  };

  const handleModeSwitch = (newMode: 'chat' | 'voice') => {
    setMode(newMode);
    setCurrentConversationId(null);
    setSidebarOpen(false);
  };

  return (
    <>
      {/* Sidebar drawer */}
      <div
        className={`fixed top-0 left-0 h-full bg-white shadow-2xl z-30 transition-transform duration-300 ease-in-out w-[80vw] max-w-[400px] flex flex-col ${
          sidebarOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        {/* Header */}
        <div className="flex-shrink-0 px-4 py-4 border-b border-gray-100">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-lg font-bold text-gray-800">历史对话</h2>
            <button
              onClick={() => setSidebarOpen(false)}
              className="p-1.5 rounded-lg hover:bg-gray-100 transition-colors"
            >
              <svg className="w-5 h-5 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Mode switch */}
          <div className="flex rounded-lg bg-primary-50 p-0.5 mb-3">
            <button
              onClick={() => handleModeSwitch('chat')}
              className={`flex-1 py-1.5 text-sm rounded-md transition-colors ${
                mode === 'chat' ? 'bg-white text-primary-700 font-medium shadow-sm' : 'text-gray-500'
              }`}
            >
              💬 Chat
            </button>
            <button
              onClick={() => handleModeSwitch('voice')}
              className={`flex-1 py-1.5 text-sm rounded-md transition-colors ${
                mode === 'voice' ? 'bg-white text-primary-700 font-medium shadow-sm' : 'text-gray-500'
              }`}
            >
              🎧 Voice
            </button>
          </div>

          {/* Search */}
          <div className="relative">
            <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input
              type="text"
              placeholder="搜索对话..."
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
              className="w-full pl-9 pr-3 py-2 text-sm rounded-lg border border-gray-200 bg-gray-50 focus:outline-none focus:ring-2 focus:ring-primary-300 focus:border-transparent"
            />
          </div>
        </div>

        {/* Conversation list */}
        <div className="flex-1 overflow-y-auto">
          {grouped.map((group) => (
            <div key={group.label} className="px-3 py-2">
              <div className="text-xs text-gray-400 font-medium px-3 py-1.5 uppercase tracking-wider">
                {group.label}
              </div>
              {group.items.map((conv) => (
                <div
                  key={conv.id}
                  onClick={() => handleSelectConversation(conv.id)}
                  className={`group flex items-center gap-3 px-3 py-2.5 rounded-lg cursor-pointer transition-colors mb-0.5 ${
                    currentConversationId === conv.id
                      ? 'bg-primary-100 text-primary-800'
                      : 'hover:bg-gray-50 text-gray-700'
                  }`}
                >
                  <span className="text-lg flex-shrink-0">
                    {conv.mode === 'voice' ? '🎧' : '💬'}
                  </span>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">{conv.title}</div>
                    {conv.last_message_preview && (
                      <div className="text-xs text-gray-400 truncate mt-0.5">
                        {conv.last_message_preview}
                      </div>
                    )}
                  </div>
                  <button
                    onClick={(e) => handleDeleteConversation(e, conv.id)}
                    className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-red-100 text-gray-400 hover:text-red-500 transition-all"
                  >
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              ))}
            </div>
          ))}

          {filteredConversations.length === 0 && (
            <div className="text-center text-gray-400 py-12">
              <div className="text-4xl mb-3">💬</div>
              <p className="text-sm">{searchText ? '没有找到匹配的对话' : '还没有对话记录'}</p>
              <button
                onClick={handleNewChat}
                className="mt-3 text-sm text-primary-500 hover:text-primary-600 font-medium"
              >
                开始新对话
              </button>
            </div>
          )}
        </div>

        {/* User info footer */}
        <div className="flex-shrink-0 border-t border-gray-100 p-3">
          <button
            onClick={() => setShowUserMenu(true)}
            className="flex items-center gap-3 w-full p-2 rounded-lg hover:bg-gray-50 transition-colors"
          >
            <div className="w-9 h-9 rounded-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center text-white text-sm font-bold overflow-hidden">
              {user?.avatar_url ? (
                <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
              ) : (
                (user?.nickname || user?.username || '游').charAt(0).toUpperCase()
              )}
            </div>
            <div className="flex-1 text-left">
              <div className="text-sm font-medium text-gray-800">
                {isLoggedIn ? (user?.nickname || user?.username) : '游客'}
              </div>
              <div className="text-xs text-gray-400">
                {isLoggedIn ? user?.username : '点击登录'}
              </div>
            </div>
            <svg className="w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>
      </div>

      {/* User menu modal */}
      {showUserMenu && <UserMenu onClose={() => setShowUserMenu(false)} />}
    </>
  );
}

function UserMenu({ onClose }: { onClose: () => void }) {
  const { user, isLoggedIn, logout } = useAuthStore();
  const { setShowSettingsModal } = useUIStore();

  const handleLogout = async () => {
    await fetch('/api/auth/logout', { method: 'POST', credentials: 'include' });
    logout();
    onClose();
  };

  const handleOpenSettings = () => {
    setShowSettingsModal(true);
    onClose();
  };

  if (!isLoggedIn) {
    return (
      <div className="fixed inset-0 bg-black/30 z-50 flex items-center justify-center p-4" onClick={onClose}>
        <div className="bg-white rounded-2xl shadow-xl p-6 w-full max-w-sm" onClick={(e) => e.stopPropagation()}>
          <h3 className="text-lg font-bold text-gray-800 mb-4">登录 / 注册</h3>
          <AuthForm onClose={onClose} />
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-black/30 z-50 flex items-end md:items-center justify-center" onClick={onClose}>
      <div className="bg-white rounded-t-2xl md:rounded-2xl shadow-xl p-6 w-full max-w-sm animate-slide-up" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center gap-3 mb-4">
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center text-white text-lg font-bold">
            {(user?.nickname || user?.username || 'U').charAt(0).toUpperCase()}
          </div>
          <div>
            <div className="font-semibold text-gray-800">{user?.nickname || user?.username}</div>
            <div className="text-sm text-gray-500">@{user?.username}</div>
          </div>
        </div>

        <div className="space-y-1">
          <button
            onClick={handleOpenSettings}
            className="w-full text-left px-4 py-2.5 rounded-lg hover:bg-gray-50 flex items-center gap-3 text-gray-700"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.066 2.573c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.573 1.066c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.066-2.573c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
            个人设置
          </button>
          <button
            onClick={handleLogout}
            className="w-full text-left px-4 py-2.5 rounded-lg hover:bg-red-50 flex items-center gap-3 text-red-600"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
            退出登录
          </button>
        </div>
        <button onClick={onClose} className="w-full mt-3 py-2 text-sm text-gray-400 hover:text-gray-600">
          取消
        </button>
      </div>
    </div>
  );
}

function AuthForm({ onClose }: { onClose: () => void }) {
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [nickname, setNickname] = useState('');
  const [error, setError] = useState('');
  const { fetchMe } = useAuthStore();
  const { showToast } = useUIStore();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const endpoint = isLogin ? '/api/auth/login' : '/api/auth/register';
    const body: Record<string, string> = { username, password };
    if (!isLogin && nickname) body.nickname = nickname;

    try {
      const resp = await fetch(endpoint, {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (resp.ok) {
        await fetchMe();
        showToast(isLogin ? '登录成功' : '注册成功', 'success');
        onClose();
      } else {
        const data = await resp.json();
        setError(data.detail || '操作失败');
      }
    } catch {
      setError('网络错误，请重试');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-3">
      <input
        type="text"
        placeholder="用户名"
        value={username}
        onChange={(e) => setUsername(e.target.value)}
        className="w-full px-4 py-2.5 rounded-xl border border-gray-200 bg-gray-50 focus:outline-none focus:ring-2 focus:ring-primary-300 text-sm"
        required
        minLength={3}
      />
      <input
        type="password"
        placeholder="密码"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        className="w-full px-4 py-2.5 rounded-xl border border-gray-200 bg-gray-50 focus:outline-none focus:ring-2 focus:ring-primary-300 text-sm"
        required
        minLength={6}
      />
      {!isLogin && (
        <input
          type="text"
          placeholder="昵称（可选）"
          value={nickname}
          onChange={(e) => setNickname(e.target.value)}
          className="w-full px-4 py-2.5 rounded-xl border border-gray-200 bg-gray-50 focus:outline-none focus:ring-2 focus:ring-primary-300 text-sm"
        />
      )}
      {error && <p className="text-red-500 text-sm">{error}</p>}
      <button
        type="submit"
        className="w-full py-2.5 rounded-xl bg-primary-500 hover:bg-primary-600 text-white font-medium transition-colors"
      >
        {isLogin ? '登录' : '注册'}
      </button>
      <button
        type="button"
        onClick={() => { setIsLogin(!isLogin); setError(''); }}
        className="w-full text-sm text-primary-500 hover:text-primary-600"
      >
        {isLogin ? '没有账号？去注册' : '已有账号？去登录'}
      </button>
    </form>
  );
}

import { create } from 'zustand';
import type { User, UserSettings, Conversation, Message, ModelInfo } from '../types';

// --- Auth Store ---
interface AuthState {
  user: User | null;
  isLoggedIn: boolean;
  isLoading: boolean;
  guestId: string;
  setUser: (user: User | null) => void;
  setLoading: (loading: boolean) => void;
  logout: () => void;
  initGuest: () => void;
  fetchMe: () => Promise<void>;
}

export const useAuthStore = create<AuthState>((set, get) => ({
  user: null,
  isLoggedIn: false,
  isLoading: true,
  guestId: '',

  setUser: (user) => set({ user, isLoggedIn: !!user }),
  setLoading: (loading) => set({ isLoading: loading }),

  logout: () => {
    set({ user: null, isLoggedIn: false });
    // Guest mode after logout
    const guestId = localStorage.getItem('guest_id');
    if (!guestId) {
      const newId = 'g_' + Math.random().toString(36).substring(2, 18);
      localStorage.setItem('guest_id', newId);
      set({ guestId: newId });
    } else {
      set({ guestId });
    }
  },

  initGuest: () => {
    let guestId = localStorage.getItem('guest_id');
    if (!guestId) {
      guestId = 'g_' + Math.random().toString(36).substring(2, 18);
      localStorage.setItem('guest_id', guestId);
    }
    set({ guestId, isLoading: false });
  },

  fetchMe: async () => {
    try {
      set({ isLoading: true });
      const resp = await fetch('/api/auth/me', { credentials: 'include' });
      if (resp.ok) {
        const user = await resp.json();
        set({ user, isLoggedIn: true, isLoading: false });
      } else {
        get().initGuest();
      }
    } catch {
      get().initGuest();
    }
  },
}));

// --- UI Store ---
interface UIState {
  sidebarOpen: boolean;
  mode: 'chat' | 'voice';
  currentConversationId: string | null;
  toastMessage: string | null;
  toastType: 'success' | 'error' | 'info';
  showSettingsModal: boolean;
  showModelSelector: boolean;
  showMergeDialog: boolean;
  searchQuery: string;

  setSidebarOpen: (open: boolean) => void;
  toggleSidebar: () => void;
  setMode: (mode: 'chat' | 'voice') => void;
  setCurrentConversationId: (id: string | null) => void;
  showToast: (message: string, type?: 'success' | 'error' | 'info') => void;
  hideToast: () => void;
  setShowSettingsModal: (show: boolean) => void;
  setShowModelSelector: (show: boolean) => void;
  setShowMergeDialog: (show: boolean) => void;
  setSearchQuery: (q: string) => void;
}

export const useUIStore = create<UIState>((set) => ({
  sidebarOpen: false,
  mode: 'chat',
  currentConversationId: null,
  toastMessage: null,
  toastType: 'info',
  showSettingsModal: false,
  showModelSelector: false,
  showMergeDialog: false,
  searchQuery: '',

  setSidebarOpen: (open) => set({ sidebarOpen: open }),
  toggleSidebar: () => set((s) => ({ sidebarOpen: !s.sidebarOpen })),
  setMode: (mode) => set({ mode }),
  setCurrentConversationId: (id) => set({ currentConversationId: id }),
  showToast: (message, type = 'info') => {
    set({ toastMessage: message, toastType: type });
    setTimeout(() => set({ toastMessage: null }), 3000);
  },
  hideToast: () => set({ toastMessage: null }),
  setShowSettingsModal: (show) => set({ showSettingsModal: show }),
  setShowModelSelector: (show) => set({ showModelSelector: show }),
  setShowMergeDialog: (show) => set({ showMergeDialog: show }),
  setSearchQuery: (q) => set({ searchQuery: q }),
}));

// --- Model Store ---
interface ModelState {
  models: ModelInfo[];
  selectedModelId: string;
  isLoading: boolean;
  fetchModels: () => Promise<void>;
  setSelectedModel: (id: string) => void;
  getSelectedModel: () => ModelInfo | undefined;
}

export const useModelStore = create<ModelState>((set, get) => ({
  models: [],
  selectedModelId: 'openrouter/auto',
  isLoading: false,

  fetchModels: async () => {
    set({ isLoading: true });
    try {
      const resp = await fetch('/api/models');
      const data = await resp.json();
      set({ models: data.models || [], isLoading: false });
    } catch {
      set({ isLoading: false });
    }
  },
  setSelectedModel: (id) => set({ selectedModelId: id }),
  getSelectedModel: () => {
    const { models, selectedModelId } = get();
    return models.find((m) => m.id === selectedModelId);
  },
}));

// --- Conversation Store ---
interface ConversationState {
  conversations: Conversation[];
  currentMessages: Message[];
  isLoadingConversations: boolean;
  isLoadingMessages: boolean;
  isStreaming: boolean;
  streamingContent: string;
  abortController: AbortController | null;

  fetchConversations: () => Promise<void>;
  createConversation: (title: string, mode: string, modelId?: string) => Promise<Conversation | null>;
  deleteConversation: (id: string) => Promise<void>;
  updateConversation: (id: string, data: Partial<Conversation>) => Promise<void>;
  fetchMessages: (conversationId: string, page?: number) => Promise<void>;
  saveMessage: (convId: string, role: string, content: string, modelId?: string) => Promise<void>;
  deleteMessage: (messageId: string) => Promise<void>;
  sendChatMessage: (convId: string, message: string, modelId: string, imageUrls?: string[]) => Promise<void>;
  stopStreaming: () => void;
  setStreamingContent: (content: string) => void;
  appendStreamingContent: (content: string) => void;
  clearMessages: () => void;
}

export const useConversationStore = create<ConversationState>((set, get) => ({
  conversations: [],
  currentMessages: [],
  isLoadingConversations: false,
  isLoadingMessages: false,
  isStreaming: false,
  streamingContent: '',
  abortController: null,

  fetchConversations: async () => {
    set({ isLoadingConversations: true });
    try {
      const guestId = useAuthStore.getState().guestId;
      const headers: Record<string, string> = {};
      if (guestId && !useAuthStore.getState().isLoggedIn) {
        headers['x-guest-id'] = guestId;
      }
      const resp = await fetch('/api/conversations', { credentials: 'include', headers });
      const data = await resp.json();
      set({ conversations: data, isLoadingConversations: false });
    } catch {
      set({ isLoadingConversations: false });
    }
  },

  createConversation: async (title, mode, modelId) => {
    const guestId = useAuthStore.getState().guestId;
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (guestId && !useAuthStore.getState().isLoggedIn) {
      headers['x-guest-id'] = guestId;
    }
    try {
      const resp = await fetch('/api/conversations', {
        method: 'POST',
        credentials: 'include',
        headers,
        body: JSON.stringify({ title, mode, model_id: modelId }),
      });
      if (resp.ok) {
        const conv = await resp.json();
        set((s) => ({ conversations: [conv, ...s.conversations] }));
        return conv;
      }
    } catch (e) {
      console.error('Create conversation failed:', e);
    }
    return null;
  },

  deleteConversation: async (id) => {
    const guestId = useAuthStore.getState().guestId;
    const headers: Record<string, string> = {};
    if (guestId && !useAuthStore.getState().isLoggedIn) {
      headers['x-guest-id'] = guestId;
    }
    try {
      await fetch(`/api/conversations/${id}`, {
        method: 'DELETE',
        credentials: 'include',
        headers,
      });
      set((s) => ({
        conversations: s.conversations.filter((c) => c.id !== id),
      }));
    } catch (e) {
      console.error('Delete conversation failed:', e);
    }
  },

  updateConversation: async (id, data) => {
    try {
      await fetch(`/api/conversations/${id}`, {
        method: 'PUT',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
      set((s) => ({
        conversations: s.conversations.map((c) =>
          c.id === id ? { ...c, ...data } : c
        ),
      }));
    } catch (e) {
      console.error('Update conversation failed:', e);
    }
  },

  fetchMessages: async (conversationId, page = 1) => {
    set({ isLoadingMessages: true });
    const guestId = useAuthStore.getState().guestId;
    const headers: Record<string, string> = {};
    if (guestId && !useAuthStore.getState().isLoggedIn) {
      headers['x-guest-id'] = guestId;
    }
    try {
      const resp = await fetch(
        `/api/conversations/${conversationId}/messages?page=${page}&page_size=50`,
        { credentials: 'include', headers }
      );
      const data = await resp.json();
      if (page === 1) {
        set({ currentMessages: data.messages || [], isLoadingMessages: false });
      } else {
        set((s) => ({
          currentMessages: [...(data.messages || []), ...s.currentMessages],
          isLoadingMessages: false,
        }));
      }
    } catch {
      set({ isLoadingMessages: false });
    }
  },

  saveMessage: async (convId, role, content, modelId) => {
    const guestId = useAuthStore.getState().guestId;
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (guestId && !useAuthStore.getState().isLoggedIn) {
      headers['x-guest-id'] = guestId;
    }
    try {
      const resp = await fetch(`/api/conversations/${convId}/messages`, {
        method: 'POST',
        credentials: 'include',
        headers,
        body: JSON.stringify({ role, content, model_id: modelId, status: 'completed' }),
      });
      if (resp.ok) {
        const msg = await resp.json();
        set((s) => ({
          currentMessages: [...s.currentMessages, msg],
        }));
      }
    } catch (e) {
      console.error('Save message failed:', e);
    }
  },

  deleteMessage: async (messageId) => {
    try {
      await fetch(`/api/messages/${messageId}`, {
        method: 'DELETE',
        credentials: 'include',
      });
      set((s) => ({
        currentMessages: s.currentMessages.filter((m) => m.id !== messageId),
      }));
    } catch (e) {
      console.error('Delete message failed:', e);
    }
  },

  sendChatMessage: async (convId, message, modelId, imageUrls) => {
    const abortController = new AbortController();
    set({ isStreaming: true, streamingContent: '', abortController });

    // Add user message to list immediately
    const userMsg: Message = {
      id: 'temp-' + Date.now(),
      conversation_id: convId,
      role: 'user',
      content: message,
      model_id: modelId,
      status: 'completed',
      created_at: new Date().toISOString(),
    };
    set((s) => ({ currentMessages: [...s.currentMessages, userMsg] }));

    // Save user message to backend
    const guestId = useAuthStore.getState().guestId;
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (guestId && !useAuthStore.getState().isLoggedIn) {
      headers['x-guest-id'] = guestId;
    }
    try {
      const saveResp = await fetch(`/api/conversations/${convId}/messages`, {
        method: 'POST',
        credentials: 'include',
        headers,
        body: JSON.stringify({ role: 'user', content: message, model_id: modelId, status: 'completed' }),
      });
      if (saveResp.ok) {
        const savedMsg = await saveResp.json();
        set((s) => ({
          currentMessages: s.currentMessages.map((m) =>
            m.id === userMsg.id ? savedMsg : m
          ),
        }));
      }
    } catch {}

    // Start streaming
    let fullContent = '';
    try {
      const resp = await fetch('/api/chat/stream', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          conversation_id: convId,
          model_id: modelId,
          message,
          image_urls: imageUrls,
        }),
        signal: abortController.signal,
      });

      const reader = resp.body?.getReader();
      if (!reader) throw new Error('No reader');

      const decoder = new TextDecoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const data = line.slice(6);
            if (data === '[DONE]') break;
            try {
              const parsed = JSON.parse(data);
              if (parsed.content) {
                fullContent += parsed.content;
                set({ streamingContent: fullContent });
              }
              if (parsed.error) {
                useUIStore.getState().showToast(parsed.error, 'error');
              }
            } catch {}
          }
        }
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        useUIStore.getState().showToast('Stream failed: ' + err.message, 'error');
      }
    }

    set({ isStreaming: false });

    // Save assistant message
    if (fullContent) {
      const assistantMsg: Message = {
        id: 'temp-assistant-' + Date.now(),
        conversation_id: convId,
        role: 'assistant',
        content: fullContent,
        model_id: modelId,
        status: 'completed',
        created_at: new Date().toISOString(),
      };
      set((s) => ({ currentMessages: [...s.currentMessages, assistantMsg] }));

      // Save to backend
      try {
        const saveResp = await fetch(`/api/conversations/${convId}/messages`, {
          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ role: 'assistant', content: fullContent, model_id: modelId, status: 'completed' }),
        });
        if (saveResp.ok) {
          const savedMsg = await saveResp.json();
          set((s) => ({
            currentMessages: s.currentMessages.map((m) =>
              m.id === assistantMsg.id ? savedMsg : m
            ),
          }));
        }
      } catch {}

      // Refresh conversation list
      get().fetchConversations();
    }

    set({ streamingContent: '', abortController: null });
  },

  stopStreaming: () => {
    const { abortController } = get();
    if (abortController) {
      abortController.abort();
      set({ isStreaming: false, abortController: null });
    }
  },

  setStreamingContent: (content) => set({ streamingContent: content }),
  appendStreamingContent: (content) => set((s) => ({ streamingContent: s.streamingContent + content })),
  clearMessages: () => set({ currentMessages: [] }),
}));

